/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormDataSourceEventHandler(formDataSourceStr(PurchAgreementHistory, PurchAgreementHeaderHistory), FormDataSourceEventType::Activated)]
public static void PurchAgreementHeaderHistory_OnActivated(FormDataSource sender, FormDataSourceEventArgs e)
{
    FormRun element = sender.formRun();

    FormControl fc = element.design().controlName('PurchAgreementConfirmationOriginal');
    FormControl fcRpt = element.design().controlName('ETG_AgreementConfirmationRpt');
    FormControl fcACF = element.design().controlName('ETGPurchAgreementFormatForACF');        

    if(curExt() == "O001")
    {
        fc.visible(true);
        fcRpt.visible(false);
        fcACF.visible(true);
    }
    else if(curExt() == "U008")
    {
        fc.visible(true);
    }
    else
    {
        fc.visible(false);
        fcRpt.visible(true);
        fcACF.visible(false);
    }
}

